var _visibleInterval = null;
function _sendVisibleSignal() {
  // The server treats this event as user activity (resets the 30s idle
  // clock that gates push eligibility). A visible-but-unfocused window
  // (behind another app, second monitor) must NOT send it, or the user
  // can never go idle and never receives a push while the window is open.
  if (!document.hasFocus()) { dbg('[VIS] keepalive skipped: window not focused'); return; }
  if (ws && ws.readyState === 1) wsSend('visible', {});
}
function _startVisibleKeepalive() {
  if (_visibleInterval || document.hidden) return;
  _sendVisibleSignal();
  _visibleInterval = setInterval(function() {
    if (document.hidden) { clearInterval(_visibleInterval); _visibleInterval = null; return; }
    _sendVisibleSignal();
  }, 20000);
}
_startVisibleKeepalive();
window.addEventListener('focus', function() {
  dbg('[VIS] window focused, sending visible signal');
  _sendVisibleSignal();
});
document.addEventListener('visibilitychange', function() {
  if (document.hidden) {
    try { navigator.sendBeacon('/chat/api/push/idle'); } catch(e) {}
    if (_visibleInterval) { clearInterval(_visibleInterval); _visibleInterval = null; }
  } else {
    _startVisibleKeepalive();
  }
});
